// ============================================================
// IngestionWorker — Préparer l'appel à l'IngestionAgent
// ============================================================
// Le queue-service envoie :
//   { queue_name, job_id, attempt, ...original_data }
// On reconstruit le format attendu par l'IngestionAgent :
//   { message_id, correlation_id, batch: [...] }
// ============================================================

const input = $input.first().json.body || $input.first().json;
const now = new Date();

// L'item original venant de l'Orchestrateur
const item = { ...input };
delete item.queue_name;
delete item.job_id;
delete item.attempt;
delete item._attempts;
delete item._priority;
delete item._delay_ms;

const hex = Array.from({ length: 6 }, () =>
  Math.floor(Math.random() * 16).toString(16).toUpperCase()
).join('');

return [{
  json: {
    message_id: `MSG-${now.getFullYear()}-${hex}`,
    correlation_id: input.correlation_id || `CORR-${hex}`,
    timestamp: now.toISOString(),
    source: 'QUEUE_SERVICE',
    target: 'INGESTION_AGENT',
    action: 'PROCESS_BATCH',
    payload: { batch: [item] },
    batch: [item],
    // Métadonnées queue
    _queue_job_id: input.job_id,
    _queue_attempt: input.attempt || 1,
  }
}];

// ============================================================
// Analyser le résultat de l'IngestionAgent
// ============================================================
// L'IngestionAgent retourne :
//   { status, payload: { results: [...], summary: {...} } }
// Pour chaque job accepté (RECEIVED/SCHEDULED) → enqueue adaptation
// Pour chaque job rejeté → log et fin
// ============================================================

const ack = $input.first().json;
const prep = $('Préparer appel Ingestion').first().json;
const correlation_id = prep.correlation_id;

const p = ack.payload || ack;
const results = p.results || [];

const accepted = results.filter(r =>
  r.status === 'RECEIVED' || r.status === 'SCHEDULED'
);
const rejected = results.filter(r =>
  r.status !== 'RECEIVED' && r.status !== 'SCHEDULED'
);

return [{
  json: {
    correlation_id,
    batch_id: p.batch_id || '',
    accepted,
    rejected,
    has_accepted: accepted.length > 0,
    summary: p.summary || { total: results.length, accepted: accepted.length, rejected: rejected.length },
  }
}];

// ============================================================
// Enqueue chaque job accepté dans la queue 'adaptation'
// ============================================================

const data = $input.first().json;
const accepted = data.accepted || [];

return accepted.map(job => ({
  json: {
    url: 'https://barb-undefensible-dalila.ngrok-free.dev/enqueue/adaptation',
    body: {
      tenant_id: job.tenant_id,
      job_id: job.job_id,
      correlation_id: data.correlation_id,
      action: 'ADAPT_CONTENT',
      _priority: 5,
      _attempts: 3,
    }
  }
}));

// Réponse finale du worker
const data = $('Analyser résultat Ingestion').first().json;

return [{
  json: {
    worker: 'IngestionWorker',
    status: 'completed',
    correlation_id: data.correlation_id,
    accepted_count: data.accepted.length,
    rejected_count: data.rejected.length,
    enqueued_to: 'adaptation',
    timestamp: new Date().toISOString(),
  }
}];

// Aucun job accepté — rien à enqueue
const data = $input.first().json;

return [{
  json: {
    worker: 'IngestionWorker',
    status: 'completed_no_jobs',
    correlation_id: data.correlation_id,
    rejected_count: data.rejected.length,
    message: 'Tous les jobs ont été rejetés, rien à adapter',
    timestamp: new Date().toISOString(),
  }
}];
